"""
original | Isaiah | 47-48 | python3 scripts/zc-original-isaiah-47-48.py

Key translation decisions:
- Isa 47:7: olam='forever' -- Babylon's arrogant claim to eternal mistress-status
- Isa 47:8,10: the 'I am, and there is no one else beside me' formula usurps the divine I-am (43:10-11; 45:6)
- Isa 48:1: emet='truth' + tsedaqah='righteousness' -- Israel swears by YHWH but not in truth or righteousness
- Isa 48:2: qodesh='holy' city -- the holy city claim without matching holy character
- Isa 48:11: kavod='glory' -- YHWH's self-acting for his own name's sake; glory not shared
- Isa 48:16: ruach='Spirit' -- the LORD GOD's Spirit accompanies the speaker (Servant/prophet)
- Isa 48:18: shalom='peace' + tsedaqah='righteousness' -- the river/wave conditional conditional lament
- Isa 48:22: shalom='peace' -- the closing refrain: no shalom for the wicked (repeated 57:21)
"""
import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {
"47": {
"1": "<p><em>Come down and sit in the dust, O virgin daughter of Babylon.</em> The fall of Babylon is described through posture: from throne to ground-sitting. The virgin daughter imagery implies pride of untouched power -- Babylon has never been conquered. <em>Sit on the ground without a throne</em> strips the political symbol of authority: the throne gone, the ground is all that is left. The MKT preserves the address-form (<em>O virgin daughter of Babylon</em>) that treats the city as a person, allowing the shame-language to carry its full weight.</p>",
"2": "<p>The imagery of captive women grinding at the mill and wading through streams -- manual labor and exposed vulnerability. The veil removed and the robe lifted expose the formerly veiled and robed queen. The MKT's specific clothing-items (<em>veil, robe</em>) follow the Hebrew's enumeration of the stripped dignities. Each item removed is a dignity taken: the veil (identity-privacy), the robe (status-display), the shod feet (social protection).</p>",
"3": "<p>Your nakedness shall be exposed, your disgrace visible -- YHWH will take vengeance and will not relent (<em>lo efga adam</em>: I will not meet a man / not be dissuaded by anyone). The divine refusal to be negotiated out of judgment against Babylon is the counterpart to the divine compassion that could be interceded with for Israel. For Babylon, the cup of judgment is full and no mediator will succeed in emptying it.</p>",
"4": "<p>YHWH is flagged -- the parenthetical identification of Israel's Redeemer: <em>Our Redeemer -- the LORD of hosts is his name -- the Holy One of Israel.</em> The bracket-verse inserts Israel's covenant title for YHWH into the oracle against Babylon. The Redeemer who is judging Babylon is specifically Israel's covenant God. The divine name YHWH of hosts (the army commander) identifies the one bringing Babylon low as the same one who called himself Israel's Kinsman-Redeemer.</p>",
"5": "<p>Sit in silence and go into darkness, O daughter of the Chaldeans. The reversal of Babylon's previous position: formerly the mistress of kingdoms, now reduced to darkness and silence. The word <em>mistress of kingdoms</em> (<em>geveret mamlakhot</em>) is the highest political title -- over all kingdoms, not just one. The silence and darkness contrast with the Babylonian court's noise and splendor. The MKT preserves the title of greatness precisely because its loss is the point.</p>",
"6": "<p>YHWH's self-disclosure of why he used Babylon: I was angry with my people, desecrated my heritage, handed them over to you. But Babylon showed no mercy -- she went beyond the instrument-role. On the elderly she laid an extremely heavy yoke. The instrument of divine discipline overstepped its mandate: using the people for plunder rather than correction. This excess of cruelty beyond the divine assignment is what turns the instrument into the target.</p>",
"7": "<p><em>Olam</em> (ancient time, disp 3) is flagged -- Babylon said <em>I will be mistress forever.</em> The claim to eternal power is the pride that precedes the fall. <em>Le-olam</em> here means permanently, forever -- Babylon claimed a permanence that belongs only to the LORD. The failure to consider how it would end (<em>lo samti al-libbakh ahrit</em>: not set on your heart its end/outcome) is the specific failure: pride so complete that the future is not contemplated.</p>",
"8": "<p><em>Yada</em> (know, disp 2) is flagged -- <em>who says in your heart, I am, and there is no one else beside me.</em> The formula <em>ani ve-afsi od</em> (I am, and there is nothing more/no one else) is the usurpation of the divine self-description. In 45:6 and 45:18 this formula belongs to YHWH alone; here Babylon appropriates it. The widow and loss-of-children will not come -- Babylon's arrogant self-assurance is that her security is impervious. The <em>yada</em> is rendered <em>who says</em> -- the internal declaration of false omnipotence.</p>",
"9": "<p>Both losses will come in a moment, in a single day: loss of children and widowhood. The completeness of the disaster is matched by its suddenness -- a single day. Despite the great power of Babylon's enchantments and sorceries, these losses will be total. The sorcery that Babylon has practiced from youth -- the whole apparatus of Babylonian astrology and divination -- will not prevent the sudden catastrophe.</p>",
"10": "<p>You trusted in your wickedness -- the trust-vocabulary (<em>batach</em>) applied to evil as if it were a reliable foundation. <em>No one sees me</em> -- the denial of divine oversight. Your wisdom and knowledge led you astray (<em>heshi'atekha</em>: seduced/misled you) -- the Babylonian epistemic tradition (wisdom, knowledge, learning) became the agent of self-delusion. The <em>ani ve-afsi od</em> formula appears again: the knowledge that should have revealed YHWH instead reinforced self-sufficiency.</p>",
"11": "<p><em>Yada</em> (know, disp 2) is flagged twice -- evil will come <em>you will not know how to conjure away</em>, disaster <em>you will not be able to avert</em>. The two <em>yada</em>-negatives: you will not know the charm (the correct ritual for averting); you will not be able to atone for it (<em>kapper</em>: cover/atone -- the sacrificial vocabulary of dealing with wrong). The whole Babylonian system of ritual knowledge for averting evil is useless against the divine decree.</p>",
"12": "<p>The ironic invitation: stand by your enchantments and sorceries. The invitation is sarcastic -- perhaps you will succeed, perhaps you will inspire terror. The MKT's <em>perhaps you will succeed; perhaps you will inspire terror</em> preserves the ironic optative: maybe -- but both speaker and listener know it is futile. The catalogue of Babylonian occult expertise (enchantments, sorceries from youth) is precisely what will be shown to be nothing.</p>",
"13": "<p><em>Yada</em> (know, disp 2) is flagged -- the advisers who <em>divide the sky, gaze at the stars, give forecasts month by month</em> are the astrologers. <em>Let them stand up and save you</em> -- the challenge to the astrologers to do what they claim. The MKT preserves the technical astronomical vocabulary: sky-dividers, star-gazers, monthly forecasters. Babylonian astrology was technically sophisticated; Isaiah is not dismissing the observation but the claim that such observation gives power.</p>",
"14": "<p><em>Nefesh</em> (soul, disp 3) is flagged -- <em>there is no warm fire (<em>gahalah</em>) to sit beside it (<em>nefesh</em>: no coal for warming).</em> The astrologers burned up like straw -- they cannot even save themselves from the flame. No warm ember for warming oneself. The MKT notes the nefesh here as <em>not a flame warm enough to sit before.</em> The fire that consumes the astrologers gives no warmth: a fire of pure destruction, not a fire of comfort.</p>",
"15": "<p>Such are those you have dealt with -- your trading partners since your youth who now scatter, each in his own direction, with no one to save you. The commercial network (<em>sochrekhah</em>: your merchants) dissolves at the moment of crisis: each one goes off in his own direction. The social and commercial structure that depended on Babylon's power disintegrates exactly when it is most needed. The MKT's <em>trading partners</em> preserves the commercial vocabulary.</p>",
},
"48": {
"1": "<p><em>Elohim</em>, <em>emet</em> (truth, disp 2), YHWH, and <em>tsedaqah</em> (righteousness, disp 3) are all flagged -- <em>those who swear by the name of the LORD and invoke the God of Israel -- but not in truth or righteousness.</em> Israel swears by the divine name (<em>YHWH</em>) and invokes <em>Elohim</em> of Israel, but the swearing is not <em>be-emet u-vetsedaqah</em> (in truth and in righteousness). The MKT renders <em>emet</em> as <em>truth</em> and <em>tsedaqah</em> as <em>righteousness</em> -- the paired terms for the quality of covenant speech that Israel lacks while using the correct formulae.</p>",
"2": "<p><em>Elohim</em>, YHWH, and <em>qodesh</em> (holiness, disp 2) are flagged -- they call themselves after <em>the holy city</em> (<em>ir haqodesh</em>: the city of holiness) and claim to rest on <em>the God of Israel</em>. The divine name YHWH of hosts is his name. The irony: the holy city's inhabitants use the city's holiness as a credential while not sharing its holiness. The MKT's <em>holy city</em> preserves <em>ir haqodesh</em> -- the holiness attributed to the city, not to the people claiming it.</p>",
"3": "<p>The former things declared long ago went out from YHWH's mouth and were proclaimed; then suddenly the action came, and it happened. The pattern of prediction-then-fulfillment is YHWH's authentication method: the historical track record of announced-and-fulfilled events is the evidence that the same LORD who acted in the past is making new announcements that will also be fulfilled.</p>",
"4": "<p>Because I knew you are stubborn -- iron neck muscle, bronze forehead. The anatomical metaphors for stubbornness: the neck that will not bow (iron-sinewed) and the forehead that will not show shame (bronze-faced). The advance declaration of judgment was given <em>because</em> of the known stubbornness: if YHWH had waited to declare until the event, the stubborn people would have said their idols did it.</p>",
"5": "<p>I announced it from long ago, before it happened, so that you could not say, <em>My idol did it; my carved image or cast idol commanded these things.</em> The divine preemptive announcement of history is specifically designed to prevent idol-credit: the prophecy-before-fulfillment method is a form of copyright marking -- the announcement stakes the claim to the event before it happens, so no alternative claimant can appropriate the credit afterward.</p>",
"6": "<p><em>Yada</em> (know, disp 2) is flagged -- <em>you have heard; now look at all this; and will you not declare it?</em> The witness-obligation follows the hearing: after YHWH's prophetic declaration is confirmed by events, the obligation is to declare it to others. <em>From now on I announce new things, hidden things that you have not known.</em> The hidden things (<em>netsuroth</em>: kept/guarded things) are in reserve -- YHWH has not yet declared everything; a store of new announcements remains.</p>",
"7": "<p><em>Yada</em> (know, disp 2) is flagged -- <em>you cannot say, Yes, I knew them.</em> The new things are being created now, not from long ago; before today you had never heard of them. The radical newness prevents Israel's claim to prior knowledge. The refrain <em>you cannot say I already knew this</em> is the anti-self-congratulation clause: the new things belong to YHWH's initiative alone, not to Israel's perceptiveness.</p>",
"8": "<p><em>Yada</em> is flagged twice -- <em>you have not heard, you have not known; from of old your ear has not been opened.</em> The double yada-negatives (not heard, not known) describe habitual non-perception. For I knew (<em>yada</em>) that you would surely betray -- the divine knowledge of human faithlessness precedes and pre-accommodates Israel's repeated failure. The MKT's <em>from of old your ear has not been opened</em> renders the chronic failure of covenant hearing.</p>",
"9": "<p>For the sake of my name I hold back my anger; for my honor (<em>tehillati</em>: my praise/glory) I restrain it, so that I do not cut you off. The divine self-restraint is motivated by the divine name: cutting off Israel would compromise the LORD's testimony before the nations. The restraint of judgment is not because Israel deserves mercy but because YHWH's name and testimony are at stake -- the same motivation given for the wilderness-rescue in Ezek 20:9,14,22.</p>",
"10": "<p>I have refined you, but not as silver is refined -- I have tested you in the furnace of affliction. The refinement metaphor with a qualification: not as silver (completely removed from dross) but in the furnace of affliction (<em>kur oni</em>: the smelting pot of poverty/affliction). The partial character of the refining is honest: Israel has been refined but is not yet fully refined. The furnace of affliction is the Babylonian exile.</p>",
"11": "<p><em>Kavod</em> (glory, disp 2) is flagged -- <em>For my own sake, for my own sake, I act -- for how could my name be profaned? My glory I will not share with another.</em> The double <em>lema'ani lema'ani</em> (for my own sake, for my own sake) is the most emphatic possible self-reference: the motivation for acting is entirely internal to YHWH. The refusal to share <em>kavod</em> (glory) echoes 42:8: I am the LORD, I will not give my glory to another. The MKT preserves the double repetition that intensifies the divine self-motivation.</p>",
"12": "<p>Listen to me, O Jacob, and Israel, whom I called: <em>I am he; I am the first; I am also the last.</em> The I-am formula in triplicate: <em>ani hu</em> (I am he), <em>ani rishon</em> (I am first), <em>ani acharon</em> (I am also the last). Rev 1:17 and 22:13 apply this triple formula to the risen Christ: <em>I am the first and the last</em> and <em>I am the Alpha and Omega, the first and the last, the beginning and the end.</em> The MKT's exact rendering preserves the form that Revelation quotes.</p>",
"13": "<p>My hand laid the foundation of the earth, my right hand spread out the heavens; when I summon them, they take their stand together. The creation claim as the basis for the identity claim of v12: the one who is first and last is also the creator of earth and heavens. The summoning of earth and heavens to stand together is the divine command over creation -- the creator's authority over what he made. The MKT's <em>take their stand together</em> renders <em>ya'amdu yachdav</em>: they stand as one at the summons.</p>",
"14": "<p>YHWH is flagged -- <em>The LORD loves him; he shall carry out his will against Babylon, and his arm shall be against the Chaldeans.</em> The <em>him</em> is Cyrus (44:28; 45:1) -- YHWH's chosen instrument. The divine love for the instrument is notable: not merely using Cyrus but loving him and ensuring he succeeds. The MKT's <em>carry out his will</em> renders <em>ya'aseh cheftso</em>: do/accomplish his desire/pleasure.</p>",
"15": "<p>I, even I, have spoken; I have called him; I have brought him; and he will succeed in his mission. The emphatic I-statements (four first-person verbs) place the entirety of Cyrus's mission in the divine initiative: spoken, called, brought, and guaranteeing success. The MKT preserves the anaphora of the four verbs. Cyrus's success is already secured by the divine promise before it happens historically.</p>",
"16": "<p><em>Ruach</em> (Spirit, disp 4) is flagged -- <em>And now the Lord GOD has sent me, and his Spirit.</em> The speaker shifts to the first person -- either the prophet or the Servant. The claim that the Lord GOD has sent both the speaker and his Spirit creates a triad: the Lord GOD (sender), the speaker (sent), and the Spirit (also sent). The MKT's <em>his Spirit</em> capitalizes, reflecting the divine Spirit sent alongside the speaker. This verse has been interpreted as an early trinitarian formula: the LORD sending both the Son and the Spirit.</p>",
"17": "<p><em>Elohim</em> and YHWH are flagged twice -- <em>I am the LORD your God, who teaches you what is good for you, who leads you in the way you should go.</em> The double divine title (LORD your God) introduces the teaching-and-leading metaphor: YHWH as teacher and path-guide. The specificity -- <em>teaches you what is good for you</em> -- implies that YHWH's instruction is not arbitrary law but what genuinely benefits the people. The path-leading image is the Psalm 23:3 pattern.</p>",
"18": "<p><em>Tsedaqah</em> (righteousness, disp 3) and <em>shalom</em> (peace, disp 2) are flagged -- <em>If only you had listened to my commandments! Then your peace would have been like a river, and your righteousness like the waves of the sea.</em> The counterfactual lament: the peace that was available but not received. <em>Shalom</em> as a river -- the steady, broad, inexhaustible flow of covenantal wholeness. <em>Tsedaqah</em> as the waves of the sea -- the continuous, rhythmic, overwhelming rightness that should have characterized Israel's life. The MKT preserves the two similes without merging them.</p>",
"19": "<p>Your descendants would have been like sand, your children like its grains; their name would never have been cut off or destroyed before me. The conditional blessing unrealized: the Abrahamic promise of sand-numbered descendants (Gen 22:17) was available but forfeited through disobedience. The name that would never have been cut off contrasts with the real history of exile and dispersion. The lament of lost blessing is one of the most poignant moments in Second Isaiah.</p>",
"20": "<p>YHWH is flagged -- the command to go out from Babylon and flee from Chaldea, declared with joy to the ends of the earth: <em>the LORD has redeemed his servant Jacob.</em> The redemption declaration is the gospel announcement (<em>mevasser</em>: herald of good news) that runs through 40:9; 52:7; 61:1. The MKT's <em>declare this with a cry of joy</em> renders the commanded response: not quiet departure but joyful proclamation. The ends of the earth are the audience, giving the redemption of Jacob universal significance.</p>",
"21": "<p>They did not thirst when he led them through the deserts -- he made water flow from the rock. The new Exodus recall: the miracle of the rock in the wilderness (Exod 17:6; Num 20:11) is cited as the pattern for the new return from Babylon. Paul identifies the rock as Christ (1 Cor 10:4): the spiritual rock that followed them was Christ. The MKT's rendering follows the Hebrew's past-tense narrative of what YHWH did -- a historical claim, not just a metaphor.</p>",
"22": "<p>YHWH is flagged; <em>shalom</em> (peace, disp 2) is flagged -- <em>There is no peace, says the LORD, for the wicked.</em> The closing refrain of chapters 40-48 is a warning note: the redemption promises of the preceding chapters are not available to the wicked without repentance. The <em>shalom</em> that was a river (v18) is specifically denied to the <em>resha'im</em> (wicked). This refrain appears again at 57:21 as the closing statement of the second subsection (49-57), making it a structural marker of the book's sections.</p>",
},
}

def main():
    data = load_comm('mkt-original', 'isaiah')
    merge_comm(data, ISAIAH)
    chs = sorted(data.keys(), key=lambda x: int(x))
    total_v = sum(len(data[c]) for c in chs)
    print(f'Isaiah original: {len(chs)} chapters, {total_v} verses')
    save_comm('mkt-original', 'isaiah', data)

if __name__ == '__main__':
    main()
